// org.apache.commons.lang.text.StrTokenizerTest::testCloneNull
    public void testCloneNull() {
        StrTokenizer tokenizer = new StrTokenizer((char[]) null);

        assertEquals(null, tokenizer.nextToken());
        tokenizer.reset();
        assertEquals(null, tokenizer.nextToken());

